config.surfaceDefinitions.auth = {
  id: "auth",
  label: "Auth",
  pagesRoot: "auth",
  enabled: true,
  requiresAuth: false,
  requiresWorkspace: false,
  origin: ""
};

addPlacement({
  id: "auth.profile.widget",
  host: "shell-layout",
  position: "top-right",
  surfaces: ["*"],
  order: 1000,
  componentToken: "auth.web.profile.widget"
});

addPlacement({
  id: "auth.profile.menu.sign-in",
  host: "auth-profile-menu",
  position: "primary-menu",
  surfaces: ["*"],
  order: 200,
  componentToken: "auth.web.profile.menu.link-item",
  props: {
    label: "Sign in",
    to: "/auth/login"
  },
  when: ({ auth }) => !Boolean(auth?.authenticated)
});

addPlacement({
  id: "auth.profile.menu.sign-out",
  host: "auth-profile-menu",
  position: "primary-menu",
  surfaces: ["*"],
  order: 1000,
  componentToken: "auth.web.profile.menu.link-item",
  props: {
    label: "Sign out",
    to: "/auth/signout"
  },
  when: ({ auth }) => Boolean(auth?.authenticated)
});

