config.surfaceDefinitions.account = {
  id: "account",
  label: "Account",
  pagesRoot: "account",
  enabled: true,
  requiresAuth: true,
  requiresWorkspace: false,
  origin: ""
};

addPlacement({
  id: "users.profile.menu.surface-switch",
  host: "auth-profile-menu",
  position: "primary-menu",
  surfaces: ["*"],
  order: 100,
  componentToken: "users.web.profile.menu.surface-switch-item",
  when: ({ auth }) => Boolean(auth?.authenticated)
});

addPlacement({
  id: "users.profile.menu.settings",
  host: "auth-profile-menu",
  position: "primary-menu",
  surfaces: ["*"],
  order: 500,
  componentToken: "users.web.shell.menu-link-item",
  props: {
    label: "Settings",
    to: "/account"
  },
  when: ({ auth }) => Boolean(auth?.authenticated)
});

addPlacement({
  id: "users.console.menu.settings",
  host: "shell-layout",
  position: "primary-menu",
  surfaces: ["console"],
  order: 100,
  componentToken: "users.web.shell.menu-link-item",
  props: {
    label: "Settings",
    to: "/console/settings",
    icon: "mdi-cog-outline"
  },
  when: ({ auth }) => Boolean(auth?.authenticated)
});

config.surfaceDefinitions.app = {
  id: "app",
  label: "App",
  pagesRoot: "w/[workspaceSlug]",
  enabled: true,
  requiresAuth: true,
  requiresWorkspace: true,
  accessPolicyId: "workspace_member",
  origin: ""
};

config.surfaceDefinitions.admin = {
  id: "admin",
  label: "Admin",
  pagesRoot: "w/[workspaceSlug]/admin",
  enabled: true,
  requiresAuth: true,
  requiresWorkspace: true,
  accessPolicyId: "workspace_member",
  origin: ""
};

config.workspaceSwitching = true;
config.workspaceInvitations = {
  enabled: true,
  allowInPersonalMode: true
};

addPlacement({
  id: "users.workspace.selector",
  host: "shell-layout",
  position: "top-left",
  surfaces: ["*"],
  order: 200,
  componentToken: "users.web.workspace.selector",
  props: {
    allowOnNonWorkspaceSurface: true,
    targetSurfaceId: "app"
  },
  when: ({ auth }) => {
    return Boolean(auth?.authenticated);
  }
});

addPlacement({
  id: "users.account.invites.cue",
  host: "shell-layout",
  position: "top-right",
  surfaces: ["*"],
  order: 850,
  componentToken: "local.main.account.pending-invites.cue",
  when: ({ auth }) => Boolean(auth?.authenticated)
});

addPlacement({
